  "inlineSchema": "// College Admission and Finance Management System\n// Prisma Schema — PostgreSQL\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─── Enums ──────────────────────────────────────────────\n\nenum Role {\n  ADMIN\n  APPLICANT\n  STUDENT\n}\n\nenum UserStatus {\n  ACTIVE\n  INACTIVE\n}\n\nenum ApplicantStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum IntakeStatus {\n  ACTIVE\n  CLOSED\n}\n\nenum InvoiceStatus {\n  PENDING\n  PARTIAL\n  PAID\n  OVERDUE\n}\n\nenum PaymentStatus {\n  SUBMITTED\n  VERIFIED\n  REJECTED\n}\n\nenum NoticeAudience {\n  ALL\n  APPLICANTS\n  STUDENTS\n}\n\n// ─── Models ─────────────────────────────────────────────\n\nmodel User {\n  id               Int        @id @default(autoincrement())\n  email            String     @unique\n  name             String?\n  password         String\n  role             Role       @default(APPLICANT)\n  status           UserStatus @default(ACTIVE)\n  refreshToken     String?\n  resetToken       String?\n  resetTokenExpiry DateTime?\n  applicant        Applicant?\n  student          Student?\n  auditLogs        AuditLog[]\n  createdAt        DateTime   @default(now())\n  updatedAt        DateTime   @updatedAt\n\n  @@index([email])\n  @@index([role])\n  @@map(\"users\")\n}\n\nmodel Department {\n  id        Int       @id @default(autoincrement())\n  name      String\n  code      String    @unique\n  programs  Program[]\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@index([code])\n  @@map(\"departments\")\n}\n\nmodel Program {\n  id            Int            @id @default(autoincrement())\n  name          String\n  code          String         @unique\n  description   String?\n  duration      String? // e.g. \"4 years\"\n  departmentId  Int\n  department    Department     @relation(fields: [departmentId], references: [id])\n  intakes       Intake[]\n  applicants    Applicant[]\n  feeStructures FeeStructure[]\n  notices       Notice[]\n  createdAt     DateTime       @default(now())\n  updatedAt     DateTime       @updatedAt\n\n  @@index([code])\n  @@index([departmentId])\n  @@map(\"programs\")\n}\n\nmodel Intake {\n  id                  Int            @id @default(autoincrement())\n  name                String // e.g. \"Fall 2026\"\n  programId           Int\n  program             Program        @relation(fields: [programId], references: [id])\n  startDate           DateTime\n  endDate             DateTime\n  applicationDeadline DateTime\n  maxCapacity         Int            @default(100)\n  status              IntakeStatus   @default(ACTIVE)\n  applicants          Applicant[]\n  feeStructures       FeeStructure[]\n  notices             Notice[]\n  createdAt           DateTime       @default(now())\n  updatedAt           DateTime       @updatedAt\n\n  @@index([programId])\n  @@index([status])\n  @@map(\"intakes\")\n}\n\nmodel Applicant {\n  id            Int             @id @default(autoincrement())\n  firstName     String\n  lastName      String\n  email         String\n  phone         String\n  dateOfBirth   DateTime?\n  address       String?\n  nationality   String?\n  previousEdu   String? // Previous education details\n  intakeId      Int\n  intake        Intake          @relation(fields: [intakeId], references: [id])\n  programId     Int\n  program       Program         @relation(fields: [programId], references: [id])\n  status        ApplicantStatus @default(PENDING)\n  rejectionNote String?\n  submittedAt   DateTime        @default(now())\n  student       Student?\n  userId        Int?            @unique\n  user          User?           @relation(fields: [userId], references: [id])\n  createdAt     DateTime        @default(now())\n  updatedAt     DateTime        @updatedAt\n\n  @@index([email])\n  @@index([intakeId])\n  @@index([programId])\n  @@index([status])\n  @@map(\"applicants\")\n}\n\nmodel Student {\n  id          Int       @id @default(autoincrement())\n  studentId   String    @unique // e.g. \"STU-2026-001\"\n  applicantId Int       @unique\n  applicant   Applicant @relation(fields: [applicantId], references: [id])\n  userId      Int       @unique\n  user        User      @relation(fields: [userId], references: [id])\n  enrolledAt  DateTime  @default(now())\n  invoices    Invoice[]\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  @@index([studentId])\n  @@index([applicantId])\n  @@index([userId])\n  @@map(\"students\")\n}\n\nmodel FeeStructure {\n  id        Int       @id @default(autoincrement())\n  name      String // e.g. \"Tuition Fee\", \"Registration Fee\"\n  amount    Float\n  currency  String    @default(\"USD\")\n  programId Int\n  program   Program   @relation(fields: [programId], references: [id])\n  intakeId  Int?\n  intake    Intake?   @relation(fields: [intakeId], references: [id])\n  invoices  Invoice[]\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  @@index([programId])\n  @@index([intakeId])\n  @@map(\"fee_structures\")\n}\n\nmodel Invoice {\n  id             Int           @id @default(autoincrement())\n  invoiceNumber  String        @unique // e.g. \"INV-2026-001\"\n  studentId      Int\n  student        Student       @relation(fields: [studentId], references: [id])\n  feeStructureId Int\n  feeStructure   FeeStructure  @relation(fields: [feeStructureId], references: [id])\n  amount         Float\n  paidAmount     Float         @default(0)\n  dueDate        DateTime\n  status         InvoiceStatus @default(PENDING)\n  payments       Payment[]\n  createdAt      DateTime      @default(now())\n  updatedAt      DateTime      @updatedAt\n\n  @@index([studentId])\n  @@index([feeStructureId])\n  @@index([status])\n  @@index([invoiceNumber])\n  @@map(\"invoices\")\n}\n\nmodel Payment {\n  id          Int           @id @default(autoincrement())\n  invoiceId   Int\n  invoice     Invoice       @relation(fields: [invoiceId], references: [id])\n  amount      Float\n  method      String // e.g. \"BANK_TRANSFER\", \"CASH\", \"CARD\"\n  proofUrl    String? // File path to payment proof\n  reference   String? // Transaction reference\n  status      PaymentStatus @default(SUBMITTED)\n  notes       String? // Admin notes on verification\n  verifiedAt  DateTime?\n  paymentDate DateTime      @default(now())\n  createdAt   DateTime      @default(now())\n  updatedAt   DateTime      @updatedAt\n\n  @@index([invoiceId])\n  @@index([status])\n  @@map(\"payments\")\n}\n\nmodel Notice {\n  id          Int            @id @default(autoincrement())\n  title       String\n  content     String\n  audience    NoticeAudience @default(ALL)\n  programId   Int?\n  program     Program?       @relation(fields: [programId], references: [id])\n  intakeId    Int?\n  intake      Intake?        @relation(fields: [intakeId], references: [id])\n  isPublished Boolean        @default(true)\n  expiryDate  DateTime?\n  createdAt   DateTime       @default(now())\n  updatedAt   DateTime       @updatedAt\n\n  @@index([audience])\n  @@index([programId])\n  @@index([intakeId])\n  @@index([isPublished])\n  @@map(\"notices\")\n}\n\nmodel AuditLog {\n  id        Int      @id @default(autoincrement())\n  userId    Int\n  user      User     @relation(fields: [userId], references: [id])\n  action    String // e.g. \"CREATE\", \"UPDATE\", \"DELETE\", \"APPROVE\", \"REJECT\"\n  entity    String // e.g. \"Applicant\", \"Invoice\", \"Payment\"\n  entityId  String\n  details   String? // JSON string with details\n  ipAddress String?\n  timestamp DateTime @default(now())\n\n  @@index([userId])\n  @@index([entity])\n  @@index([entityId])\n  @@index([timestamp])\n  @@map(\"audit_logs\")\n}\n",
